class Solution:
    def reverse(self, x: int) -> int:
        sign = -1 if x < 0 else 1
        x *= sign
        res = 0
        while x:
            digit = x % 10
            x //= 10
            if res > (2**31 - 1 - digit) // 10:
                return 0
            res = res * 10 + digit
        return sign * res

